cardCss:
/*
 * YOU DIED
 * ─────────────────────────────────────────────────────────────────────────
 * Aesthetic : Dark Souls / FromSoftware death screen
 * Fonts     : Cinzel (Google Fonts) — Roman-era serif; evokes stone carvings
 * Palette   : #000 background · #D4C5A9 bone · #C0392B ember red · #666 ash
 * Background: radial-gradient from dark red center to pure black edges
 * Vignette  : absolute inset radial-gradient overlay, transparent center,
 *             rgba black at edges — deepens the sense of tunnel vision
 * Text glow : text-shadow in blood-red on the term; ember glow on the
 *             "YOU RECALLED" banner via multi-stop text-shadow spread
 * Images    : filter brightness(0.65) sepia(0.4) — aged, drained of color
 * Input     : borderless except a single bottom rule that glows red on focus
 */

@import url("https://fonts.googleapis.com/css2?family=Cinzel:wght@400;700;900&display=swap");

:root {
  --blood: #8B1A1A;
  --ember: #C0392B;
  --bone:  #D4C5A9;
  --ash:   #666;
}

.card {
  background: #000;
  color: var(--bone);
  font-family: "Cinzel", serif;
  min-height: 100%;
}

.died-card {
  background: radial-gradient(ellipse at 50% 50%, #1e0000 0%, #0a0000 55%, #000 100%);
  min-height: 100%;
  position: relative;
  overflow: hidden;
}

.died-flex-center {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

.died-vignette {
  position: absolute;
  inset: 0;
  background: radial-gradient(ellipse at center, transparent 30%, rgba(0,0,0,0.85) 100%);
  pointer-events: none;
}

.died-content {
  position: relative;
  z-index: 1;
  text-align: center;
  padding: 4rem 3rem;
}

.died-recalled {
  position: absolute;
  top: 1.25rem;
  left: 0; right: 0;
  text-align: center;
  font-size: 2.2rem;
  font-weight: 900;
  letter-spacing: 0.45em;
  text-transform: uppercase;
  color: var(--ember);
  text-shadow: 0 0 18px rgba(192,57,43,0.9), 0 0 40px rgba(192,57,43,0.4);
  z-index: 1;
  margin: 0;
}

.died-term {
  font-size: 6rem;
  font-weight: 900;
  letter-spacing: 0.08em;
  color: var(--bone);
  text-shadow: 0 0 40px rgba(139,26,26,0.6);
  margin: 0 0 1rem;
  line-height: 1.1;
}

.died-prompt {
  font-size: 1.6rem;
  letter-spacing: 0.35em;
  text-transform: uppercase;
  color: var(--ash);
  margin: 0 0 1rem;
}

.died-reading {
  font-size: 3.2rem;
  color: #aaa;
  letter-spacing: 0.04em;
  margin: 0.5rem 0;
}

.died-translation {
  font-size: 2.4rem;
  color: var(--bone);
  opacity: 0.82;
  margin: 0.5rem 0;
}

.died-transliteration {
  font-size: 2rem;
  color: var(--ash);
  font-style: italic;
  margin: 0.5rem 0;
}

.died-tags {
  font-size: 1.4rem;
  color: var(--blood);
  letter-spacing: 0.22em;
  text-transform: uppercase;
  margin: 1rem 0 0;
}

.died-audio {
  color: var(--ember);
  margin: 0 0 1.5rem;
}

.died-picture img {
  max-width: 220px;
  margin-top: 1.5rem;
  filter: brightness(0.65) sepia(0.4);
  border: 1px solid var(--blood);
}

.died-input-wrap {
  margin-top: 1.5rem;
}

#input-container input {
  background-color: transparent;
  color: var(--bone);
  font-family: "Cinzel", serif;
  font-size: 2rem;
  padding: 0.5rem 0;
  border: none;
  border-bottom: 1px solid var(--blood);
  width: 100%;
  text-align: center;
}

#input-container input::placeholder {
  color: var(--ash);
  opacity: 0.6;
}

#input-container input:focus {
  outline: none;
  border-bottom-color: var(--ember);
}

.died-hint-wrap {
  margin-top: 1rem;
}

.died-hint-link {
  font-size: 1.4rem;
  color: var(--ash);
  text-decoration: underline;
  cursor: pointer;
  letter-spacing: 0.1em;
}

.died-hint-text {
  font-size: 1.4rem;
  color: var(--blood);
  letter-spacing: 0.15em;
  margin-top: 0.5rem;
}

.dn { display: none; }

.play-button {
  color: var(--ember);
  background: transparent;
  border: none;
  cursor: pointer;
  padding: 0;
  font-size: 3rem;
  line-height: 1;
}

.append-play-btn-text a::after { content: "▶"; color: var(--ember); }
.append-play-btn-text svg { display: none; }
.append-play-btn-text button { font-size: 3rem; cursor: pointer; padding: 0.2rem 0.4rem; }
